//! emit-amplituhedron-capture-hex — emit a BWAH amplituhedron capture
//! blob as hex to stdout.
//!
//! Mirrors `emit-wire-hex.rs`. Produces the wire body for the protocol69
//! teleport plane's POST /.aeon/amplituhedron-capture route:
//!
//!   prefix_hash = 66   (broadcast symbol)
//!   prefix_len  = 7    (local FOIL operand)
//!   layer_lo    = 0
//!   layer_hi    = 1
//!   tail_residual = vec![1.0_f32; 8]
//!
//! Note: the BWAH capture frame (`encode_capture_request`) carries the
//! tail_residual but has NO field for a kv_slab. The `vec![2.0_f32; 64]`
//! kv_slab belongs to the `AmplituhedronCache::capture` API, not the wire;
//! the capture route stores an empty kv_slab on the station side. The
//! teleport replay's geodesicLength:0 verdict depends only on the cache
//! HIT, so this blob is sufficient to prime a replay over key
//! (prefix_hash=66, prefix_len=7, layer_lo=0, layer_hi=1).
//!
//! Usage:
//!   cargo run --bin emit-amplituhedron-capture-hex
//!
//! Stdout: hex string (no whitespace, no newline).

use distributed_inference::amplituhedron_wire::{
    encode_capture_request, AmplituhedronCaptureRequest,
};

fn main() {
    // tail_residual rides the BWAH wire.
    let tail_residual: Vec<f32> = vec![1.0_f32; 8];
    // kv_slab is part of the cache API but NOT the BWAH capture frame; the
    // capture route stores an empty kv_slab. Built here only to document the
    // task's stated values; it is not serialized.
    let _kv_slab: Vec<f32> = vec![2.0_f32; 64];

    let cap = AmplituhedronCaptureRequest {
        prefix_hash: 66,
        prefix_len: 7,
        layer_lo: 0,
        layer_hi: 1,
        tail_residual,
    };

    let bytes = encode_capture_request(&cap);
    let hex: String = bytes.iter().map(|b| format!("{:02x}", b)).collect();
    print!("{}", hex);
}
